VALUES
  ('judicial-cf446b4c-moex-00284', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於刑法第154條之參與犯罪結社罪，下列敘述何者正確？', '["本罪只需行為人加入以犯罪為宗旨之結社時，犯罪即已成立，不必其後是否參與犯罪活動", "參與犯罪結社罪為接續犯", "多數共犯聚集商議如何加害共同仇敵，成立參與犯罪結社罪", "所謂犯罪之結社，必須以暴力犯罪、秘密活動為必要"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00285', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲於馬路上偷得乙的皮夾，經乙發覺後，驚呼小偷，並上前抓住甲的手，欲取回自己的皮夾時，甲為 脫免逮捕，遂用力將乙推倒在地，乙倒地受傷，甲立即攜帶該皮夾逃走。甲成立何罪？', '["私行拘禁罪", "恐嚇取財罪", "準強盜罪", "搶奪罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00286', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關刑法第149條聚眾不解散罪之規定，下列敘述何者錯誤？', '["行為人主觀上除須故意者外， 亦須具備強暴脅迫之意圖", "本罪之成立，須已受該管公務員解散命令3次以上而不解散", "本條所謂聚集3人以上，係指聚集之人數限於3人以上且隨時可以增加之情形", "本條規定之行為人，包含在場助勢之人及首謀二種"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00287', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關刑法第163條公務員縱放人犯罪之規定，下列敘述何者正確？', '["本罪之行為主體為公務員，且不以其職務上具有逮捕、拘禁人犯之公務員為限", "公務員所縱放之人犯如非屬其職務上所逮捕、拘禁之人，應構成刑法第162條之一般縱放人犯罪 ， 而非構成本罪", "本罪僅處罰故意犯，不罰過失犯", "本罪僅處罰既遂犯，不罰未遂犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00288', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '警員甲逮捕竊盜現行犯乙後，乙向甲苦苦哀求放自己一馬，甲正在猶豫時，卻因不慎鬆手而使乙迅速 掙脫逃走。關於甲之行為，下列敘述何者正確？', '["成立刑法第163條第2項公務員過失縱放或便利脫逃罪", "成立刑法第131條公務員圖利罪", "成立刑法第135條第1項妨害公務罪", "成立刑法第158條第1項僭行公務員職權罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00289', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於刑法第315條之妨害書信秘密罪，下列敘述何者錯誤？', '["本罪保護個人法益", "隱匿他人之封緘信件，亦成立本罪", "裝在信封當中而未封緘的書信，不是本罪的行為客體", "夫懷疑妻有外遇，可以任意開拆妻已封緘的書信實施檢查，不構成本罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00290', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲愛慕乙女，見乙郵寄封緘信件至鄰居丙家，心生忌妒，乃將該信件埋藏在附近公園之角落。對於甲 之行為，下列敘述何者正確？', '["不成立犯罪，僅是民事不法行為", "有罪，成立窺視他人非公開活動罪", "有罪，成立妨害書信秘密罪", "有罪，成立強制罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00291', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於偽證罪之敘述，下列何者正確？', '["證人偽證但未經具結者，不構成刑法第168條偽證罪", "鑑定人為虛偽陳述而具結者，不構成刑法第168條偽證罪", "被告虛偽自白者，構成刑法第168條偽證罪", "證人未到場作證者，構成刑法第168條偽證罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00292', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲槍擊A，為躲避刑責，甲乃出錢，央請乙出面向警方投案，並稱槍擊案是乙自己所為。有關甲、乙 刑責，下列敘述何者正確？', '["乙成立頂替罪", "甲成立頂替罪的幫助犯", "乙成立誣告罪", "甲成立頂替罪的教唆犯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00293', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於刑法第185條損壞壅塞交通或供公眾往來設備罪之敘述，下列何者錯誤？', '["壅塞陸路，致生往來之危險，成立本罪", "損壞橋樑，致生往來之危險，成立本罪", "壅塞水路，致生往來之危險，不成立本罪", "過失損壞橋樑，致生往來之危險，不成立本罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
